import org.owasp.encoder.Encode;

import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class XSSFixedCode {
    public static void main(String[] args) {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));

        try {
            System.out.print("Enter your name: ");
            String name = br.readLine();

            // Sanitize user input using OWASP Java Encoder
            String sanitizedName = Encode.forHtml(name);

            System.out.println("Hello, " + sanitizedName + "!"); // User input 'name' is now properly encoded
        } catch (IOException e) {
            System.out.println("An error occurred.");
            e.printStackTrace();
        }
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
